let Params = new URLSearchParams(window.location.search);
let id = Params.get("id");

let product = card.find(item => item.id == id);

if (product) {
    document.write(`
    <div class="continer2">
        <div class="image">
            <img src="${product.pic}">
        </div>

        <div class="content1">
            <h2>${product.produces}</h2>
            <h2>${product.Name}</h2>
            <p>${product.detail}</p>
 
            <h3>Benefit</h3>
            <p>${product.nutrition}</p>

            <label>Quantity:</label>
            <input type="number" id="qty" value="1" min="1">

            <button onclick="addToCart('${product.Name}')">
            Add to Cart
            </button>
        </div>
    </div>
    `);
}


let orderCount = 0;

function addToCart() {
    orderCount++;
    document.getElementById("orderCount").innerText = orderCount;

    alert("Product Added to Cart");
}
